package hw05.model.updateStrategies;

import provided.utils.dispatcher.IDispatcher;
import hw05.model.IBall;
import hw05.model.IBallCmd;

/**
 * An update strategy that combines two strategies into a strategy with both behaviors
 */
public class MultiStrategy implements IUpdateStrategy {

	/**
	 * The update strategy containing the first behavior
	 */
	private IUpdateStrategy firstStrategy;

	/**
	 * The update strategy containing the second behavior
	 */
	private IUpdateStrategy secondStrategy;

	/**
	 * Instantiates a MultiStrategy given two update strategies to combine
	 * @param firstStrategy the update strategy containing the first behavior
	 * @param secondStrategy the update strategy containing the second behavior
	 */
	public MultiStrategy(IUpdateStrategy firstStrategy, IUpdateStrategy secondStrategy) {
		this.firstStrategy = firstStrategy;
		this.secondStrategy = secondStrategy;
	}

	@Override
	/**
	 * Method to update state of ball based on MultiStrategy
	 * @param context the ball whose state is being updated
	 * @param disp the dispatcher that is observing the ball
	 */
	public void updateState(IBall context, IDispatcher<IBallCmd> disp) {
		firstStrategy.updateState(context, disp);
		secondStrategy.updateState(context, disp);
	}

	@Override
	public void init(IBall context) {

	}


}

package hw05.model.updateStrategies;

import java.awt.Point;

import provided.utils.dispatcher.IDispatcher;
import hw05.model.IBall;
import hw05.model.IBallCmd;
import provided.utils.displayModel.IDimension;

/**
 * An energy strategy is a strategy by which the ball gains speed by a factor of 50% 
 * when contacting the top and left boundaries of the GUI panel but loses speed 
 * by a factor of ~33% when contacting the bottom and right boundaries of the GUI panel.
 * @author akashkaranam
 */
public class EnergyStrategy implements IUpdateStrategy {

	/**
	 * float that determines how much speed increases on contact with left and top boundaries
	 */
	private float powerUp = 1.5f;
	/**
	 * float that determines how much speed decreases on contact with right and bottom boundaries
	 */
	private float powerDown = .66f;

	/**
	 * Method to change the speed of the ball based on contact with boundaries
	 * @param disp the dispatcher that makes calls to update the balls
	 */
	@Override
	public void updateState(IBall context, IDispatcher<IBallCmd> disp) {
		IDimension dim = context.getDimension();
		Point loc = context.getLocation();
		Point vel = context.getVelocity();
		int r = context.getRadius();

		if (loc.x - r <= 0 || loc.y - r <= 0) {
			context.setVelocity(new Point(Math.round(vel.x * powerUp), Math.round(vel.y * powerUp)));
		}
		if (loc.x + r >= dim.getWidth() || loc.y + r >= dim.getHeight()) {
			context.setVelocity(new Point(Math.round(vel.x * powerDown), Math.round(vel.y * powerDown)));
		}
	}

	@Override
	public void init(IBall context) {

	}


}

package hw05.model.updateStrategies;

import hw05.model.IBall;
import hw05.model.IBallCmd;
import provided.utils.dispatcher.IDispatcher;

/**
 * A criteria that allows balls with the same paint strategy to interact
 * @author charlielockyer
 *
 */
public class SamePaintCriteriaStrategy implements IUpdateStrategy{


	public void updateState(final IBall source, IDispatcher<IBallCmd> dispatcher) {
		dispatcher.updateAll(new IBallCmd() {
			@Override
			public void apply(IBall other, IDispatcher<IBallCmd> disp) {
				if (other != source) {
					if (source.getPaintStrategy().getClass().equals(other.getPaintStrategy().getClass())) {
						IBallCmd cmd = source.interactWithThen(other, disp);
						cmd.apply(source, disp);
					}
				}
			}
		});
	}

	@Override
	public void init(IBall context) {
		// TODO Auto-generated method stub

	}

}

package hw05.model.updateStrategies;

import java.awt.Color;
import hw05.model.IBall;
import hw05.model.IBallCmd;
import provided.utils.dispatcher.IDispatcher;

/**
 * A criteria that allows balls of the same (or similar, depending on threshold) color to interact
 * @author charlielockyer
 *
 */
public class SameColorCriteriaStrategy implements IUpdateStrategy{

	/**
	 * The threshold of the difference between colors
	 */
	static final int colorDistanceThreshold = 45;

	public void updateState(final IBall source, IDispatcher<IBallCmd> dispatcher) {
		dispatcher.updateAll(new IBallCmd() {
			@Override
			public void apply(IBall other, IDispatcher<IBallCmd> disp) {
				if (other != source) {
					if (colorDistance(source.getColor(), other.getColor()) < colorDistanceThreshold) {
						IBallCmd cmd = source.interactWithThen(other, disp);
						cmd.apply(source, disp);
					}
				}
			}
		});
	}

	@Override
	public void init(IBall context) {
		// TODO Auto-generated method stub

	}

	 /**
     * Calculate the color distance between two colors where the distance is the 
     * geometric distance between the two colors as points in a 3D RGB space.
     * @param color1  The first color
     * @param color2  The second color
     * @return the distance between the two colors
     */
    private double colorDistance(Color color1, Color color2) {
        int dr = color1.getRed() - color2.getRed();
        int dg = color1.getGreen() - color2.getGreen();
        int db = color1.getBlue() - color2.getBlue();
        return Math.sqrt(dr * dr + dg * dg + db * db);
    }

}

package hw05.model.updateStrategies;
import java.awt.Point;

import provided.utils.dispatcher.IDispatcher;
import hw05.model.IBall;
import hw05.model.IBallCmd;
import provided.utils.valueGenerator.impl.Randomizer;

/**
 * An update strategy that randomly sets the ball's velocity to 0
 * and then randomly restores the ball's velocity.
 */
public class LazyStrategy implements IUpdateStrategy {

	/**
	 * The velocity that the ball had before becoming lazy
	 */
	Point nonLazyVelocity;

	/**
	 * True if the strategy is currently being lazy (not moving the ball), false otherwise
	 */
	boolean isLazy = false;

	@Override
	/**
	 * Method to update ball's state according to lazy strategy
	 * @param context the ball whose state is being updated
	 * @disp the dispatcher that is observing the ball
	 */
	public void updateState(IBall context, IDispatcher<IBallCmd> disp) {
		if (isLazy) {
			if (Randomizer.Singleton.randomInt(0, 10) == 0) {
				isLazy = false;
				context.setVelocity(nonLazyVelocity);
			}
		} else {
			if (Randomizer.Singleton.randomInt(0, 10) == 0) {
				isLazy = true;
				nonLazyVelocity = new Point(context.getVelocity());
				context.setVelocity(new Point(0, 0));
			}
		}
	}

	@Override
	public void init(IBall context) {

	}


}

package hw05.model.updateStrategies;

import hw05.model.IBall;
import hw05.model.IBallCmd;
import provided.utils.dispatcher.IDispatcher;

/**
 * A criteria that allows balls that have the same speed (magnitude of velocity) to interact with one another
 * @author charlielockyer
 *
 */
public class SameSpeedCriteriaStrategy implements IUpdateStrategy{

	@Override
	public void updateState(final IBall source, IDispatcher<IBallCmd> dispatcher) {
		dispatcher.updateAll(new IBallCmd() {
			@Override
			public void apply(IBall other, IDispatcher<IBallCmd> disp) {
				if (other != source) {
					double speedSource = source.getVelocity().distance(0, 0);
					double speedOther = other.getVelocity().distance(0, 0);
					if (Math.abs(speedSource - speedOther) < 1.0) {
						IBallCmd cmd = source.interactWithThen(other, disp);
						cmd.apply(source, disp);
					}
				}
			}
		});
	}

	@Override
	public void init(IBall context) {
		// TODO Auto-generated method stub

	}

}

